head.script:
scwin.initData = {
	"observeEvent" : false,
	"minYear" : 1980,
	"maxYear" : Number(utilLib.getCurrentDate("yyyy")) + 1
};

/**
 * 화면 초기화에 필요한 로직을 수행한다.
 */
scwin.initScreen = function() {
	// 화면초기화 공통 함수 호출
	comLib.initForm($p, "ECSEC1000000", {"initScreenCallback" : scwin.searchDatas});
	//scwin.searchDatas();
};

/**
 * 화면 초기 데이터들을 조회한다.
 * @param
 * @return
 */
scwin.searchDatas = function() {
	scwin.setDashYear();
};

/**
 * 년도선택 이벤트 처리
 */
scwin.initData.dashYearEvent = false;
scwin.setDashYear = function() {
	scwin.setDashYearData();
	/*
	[...document.querySelectorAll("#" + $p.getFrameId() + " .dash-con-box-pbme .dash-water-drop-shape-con .dash-water-drop-label")].filter(emt =>
		!emt.id.endsWith("spnThsyy")).forEach(emt => {
	*/
	[...document.querySelectorAll("#" + $p.getFrameId() + " .dash-con-box-pbme .dash-water-drop-shape-con .dash-water-drop-label")].forEach(emt => {
		emt.addEventListener("click", function(e) {
			if (!scwin.initData.dashYearEvent) {
				var _this = e.target;
				scwin.initData.dashYearEvent = true;
				while(_this.tagName.toLowerCase() != "span") {
					_this = _this.parentElement;
					if (_this.tagName.toLowerCase() == "body") {
						return;
					}
				}
				var dataYear = _this.getAttribute("data-year"); // _this.textContent
				if (scwin.initData.minYear > Number(dataYear) || Number(dataYear) >= scwin.initData.maxYear) {
					scwin.initData.dashYearEvent = false;
					return;
				}
				if (_this.classList.value.includes("-prvyy")) {
					scwin.setDashYearData(Number(dataYear), "prvyy");
				} else if (_this.classList.value.includes("-nxtyy")) {
					scwin.setDashYearData(Number(dataYear), "nxtyy");
				} else {
					scwin.setDashYearData(Number(dataYear), "thsyy");
				}
			}
		});
	});
};

/**
 * 년도선택 데이터 바인딩
 */
scwin.setDashYearData = function(year, type) {
	if (!year) {
		year = Number($p.getCurrentServerDate("yyyy"));
		var isEmpty = true;
		//var isEmpty = false;
	}
	var dashYear = dmaDashYear.getJSON();
	dashYear["prvyy"] = (Number(year) - 1);
	document.getElementById(spnPrvyy.getID()).setAttribute("data-year", (Number(year) - 1));
	dashYear["thsyy"] = Number(year);
	document.getElementById(spnThsyy.getID()).setAttribute("data-year", Number(year));
	dashYear["nxtyy"] = (Number(year) + 1);
	document.getElementById(spnNxtyy.getID()).setAttribute("data-year", (Number(year) + 1));
	dmaDashYear.setJSON(dashYear);
	if (isEmpty) {
		document.getElementById(spnNxtyy.getID()).style.cursor = "not-allowed";
		var duration = 200;
		var lineHeight = 3;
		var letterSpacing = -10;
		/*
		var duration = 100;
		var lineHeight = 4.5;
		var letterSpacing = -10;
		*/
		odoo.default({
			"el" : "#" + spnPrvyy.getID(), // 타겟 Element
			"from" : "-", // 시작하는 글자
			"to" : dashYear["prvyy"], // 끝나는 글자
			"animationDelay" : 10, // 애니메이션 시작전 딜레이
			//"letterAnimationDelay" : 10, // 1글자씩 딜레이
			"lineHeight" : lineHeight, // 글자 위아래 간격
			"letterSpacing" : letterSpacing, // 글자 사이간격
			"duration": duration, // 애니메이션 진행시간(23.04.21 JS를 수정한거라 수정본 사라지지 않게 조심)
		});
		odoo.default({
			"el" : "#" + spnNxtyy.getID(),
			"from" : "-",
			"to" : dashYear["nxtyy"],
			"animationDelay" : 10,
			//"letterAnimationDelay" : 10,
			"lineHeight" : lineHeight,
			"letterSpacing" : letterSpacing,
			"duration": duration,
		});
		odoo.default({
			"el" : "#" + spnThsyy.getID(),
			"from" : "-",
			"to" : dashYear["thsyy"],
			"animationDelay" : 10,
			//"letterAnimationDelay" : 10,
			//"lineHeight" : 6.1,
			"lineHeight" : lineHeight,
			"letterSpacing" : letterSpacing,
			"duration": duration,
		});
	} else {
		var prvyyFrom = year - 1;
		var prvyyTo = year - 1;
		var nxtyyFrom = year + 1;
		var nxtyyTo = year + 1;
		var thsyyFrom = year;
		var thsyyTo = year;
		if (type == "prvyy") {
			prvyyFrom = year;
			prvyyTo = year - 1;
			nxtyyFrom = year + 2;
			nxtyyTo = year + 1;
			thsyyFrom = year + 1;
			thsyyTo = year;
		} else if (type == "nxtyy") {
			prvyyFrom = year - 2;
			prvyyTo = year - 1;
			nxtyyFrom = year;
			nxtyyTo = year + 1;
			thsyyFrom = year -1;
			thsyyTo = year;
		}
		if (scwin.initData.minYear > Number(prvyyTo)) {
			document.getElementById(spnPrvyy.getID()).style.cursor = "not-allowed";
		} else if (Number(nxtyyTo) >= scwin.initData.maxYear) {
			document.getElementById(spnNxtyy.getID()).style.cursor = "not-allowed";
		} else {
			document.getElementById(spnPrvyy.getID()).removeAttribute("style")
			document.getElementById(spnNxtyy.getID()).removeAttribute("style")
		}
		var duration = 200;
		var lineHeight = 3;
		var letterSpacing = -10;
		odoo.default({
			"el" : "#" + spnPrvyy.getID(), // 타겟 Element
			"from" : prvyyFrom, // 시작하는 글자
			"to" : prvyyTo, // 끝나는 글자
			"animationDelay" : 10, // 애니메이션 시작전 딜레이
			//"letterAnimationDelay" : 10, // 1글자씩 딜레이
			"lineHeight" : lineHeight, // 글자 위아래 간격
			"letterSpacing" : letterSpacing, // 글자 사이간격
			"duration": duration, // 애니메이션 진행시간(23.04.21 JS를 수정한거라 수정본 사라지지 않게 조심)
		});
		odoo.default({
			"el" : "#" + spnNxtyy.getID(),
			"from" : nxtyyFrom,
			"to" : nxtyyTo,
			"animationDelay" : 10,
			//"letterAnimationDelay" : 10,
			"lineHeight" : lineHeight,
			"letterSpacing" : letterSpacing,
			"duration": duration,
		});
		odoo.default({
			"el" : "#" + spnThsyy.getID(),
			"from" : thsyyFrom,
			"to" : thsyyTo,
			"animationDelay" : 10,
			//"letterAnimationDelay" : 10,
			"lineHeight" : lineHeight,
			"letterSpacing" : letterSpacing,
			"duration": duration,
		});
		setTimeout(() => {
			scwin.initData.dashYearEvent = false;
		}, 300);
	}
	scwin.setThsyyLabelClickEvent();
	scwin.serachYearData();
};

/**
 * 전주기 현황 타이틀 클릭시 이동 이벤트 등록
 */
scwin.setThsyyLabelClickEvent = function() {
	ecsLib.setMenuClickEvent(".dash-con-box-pbme .dash-list-box-bottom",
		"dash-box-con-box-",
		{
			"ECSPB100000" : "ECSPB000000",
			"ECSME100000" : "ECSME000000",
			"ECSME200000" : "ECSME000000"
		},
		{
			"p" : "ECSPB100000",
			"b" : "ECSPB100000",
			"m" : "ECSME100000",
			"e" : "ECSME200000"
		},
		{
			"year" : dmaDashYear.getJSON().thsyy
		}
	);
};

/*
 * 년도 데이터 조회
 */
scwin.serachYearData = function() {
	var dashYear = dmaDashYear.getJSON();
	scwin.searchPrvyyNxtyyData();
	scwin.searchThsyyData(dashYear["thsyy"]);
};

/**
 * 전년도 및 후년도 데이터 조회_0922
 */
scwin.searchPrvyyNxtyyData = function() {
	var dashYear = dmaDashYear.getJSON();
	var strtDt = dashYear["prvyy"];
	var endDt = dashYear["nxtyy"];

	var queryString = `?strtDt=${strtDt}`;
	queryString += `&endDt=${endDt}`;

	var option = {
		action : "ec/pbme/retrieve-pbme-sttus.do" +
			queryString,
		method : "get",
		resData : dltPrvyyNxtyyData,
		success : "scwin.searchPrvyyNxtyyDataCallBack",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
 * 전년도 및 후년도 및 금년도 라벨 데이터 조회 콜백_0922
 */
scwin.searchPrvyyNxtyyDataCallBack = function() {
	var prvyyNxtyyData = dltPrvyyNxtyyData.getAllJSON();
	var dashYear = dmaDashYear.getJSON();
	var strtDt = dashYear["prvyy"];
	var endDt = dashYear["nxtyy"];
	var year = dashYear["thsyy"];

	// 전년도 데이터 매핑
	var planCpcty = (prvyyNxtyyData.find(obj => obj.inqireDe == strtDt && obj.iemDivId == "planComptEqpCpcty") || 0).inqireIemVu;
	spnPrvyyPlanCpcty.setLabel(ecsLib.dsplFrmt(planCpcty, 2));
	var planAmt = (prvyyNxtyyData.find(obj => obj.inqireDe == strtDt && obj.iemDivId == "planComptAmt") || 0).inqireIemVu;
	spnPrvyyPlanAmt.setLabel(ecsLib.dsplFrmt(planAmt, 2));
	var planFoundng = (prvyyNxtyyData.find(obj => obj.inqireDe == strtDt && obj.iemDivId == "planFoundngCnt") || 0).inqireIemVu;
	spnPrvyyPlanFoundng.setLabel(ecsLib.dsplFrmt(planFoundng));
	var planPrgs = (prvyyNxtyyData.find(obj => obj.inqireDe == strtDt && obj.iemDivId == "planPrgsCnt") || 0).inqireIemVu;
	spnPrvyyPlanPrgs.setLabel(ecsLib.dsplFrmt(planPrgs));
	var planCompt = (prvyyNxtyyData.find(obj => obj.inqireDe == strtDt && obj.iemDivId == "planComptCnt") || 0).inqireIemVu;
	spnPrvyyPlanCompt.setLabel(ecsLib.dsplFrmt(planCompt));
	var cnstrcCpcty = (prvyyNxtyyData.find(obj => obj.inqireDe == strtDt && obj.iemDivId == "cnstrcComptEqpCpcty") || 0).inqireIemVu;
	spnPrvyyCnstrcCpcty.setLabel(ecsLib.dsplFrmt(cnstrcCpcty, 2));
	var cnstrcAmt = (prvyyNxtyyData.find(obj => obj.inqireDe == strtDt && obj.iemDivId == "cnstrcComptAmt") || 0).inqireIemVu;
	spnPrvyyCnstrcAmt.setLabel(ecsLib.dsplFrmt(cnstrcAmt, 2));
	var cnstrcFoundng = (prvyyNxtyyData.find(obj => obj.inqireDe == strtDt && obj.iemDivId == "cnstrcFoundngCnt") || 0).inqireIemVu;
	spnPrvyyCnstrcFoundng.setLabel(ecsLib.dsplFrmt(cnstrcFoundng));
	var cnstrcPrgs = (prvyyNxtyyData.find(obj => obj.inqireDe == strtDt && obj.iemDivId == "cnstrcPrgsCnt") || 0).inqireIemVu;
	spnPrvyyCnstrcPrgs.setLabel(ecsLib.dsplFrmt(cnstrcPrgs));
	var cnstrcCompt = (prvyyNxtyyData.find(obj => obj.inqireDe == strtDt && obj.iemDivId == "cnstrcComptCnt") || 0).inqireIemVu;
	spnPrvyyCnstrcCompt.setLabel(ecsLib.dsplFrmt(cnstrcCompt));
	var mngCnt = (prvyyNxtyyData.reduce((sum, obj) => obj.inqireDe == strtDt && obj.iemDivId == "mngReprMntnc" || obj.inqireDe == strtDt && obj.iemDivId == "mngRemt" || obj.inqireDe == strtDt && obj.iemDivId == "mngChckMntnc" ? sum + Number(obj.inqireIemVu) : sum, 0) || 0);
	spnPrvyyMngCnt.setLabel(ecsLib.dsplFrmt(mngCnt));
	var mngAmt = (prvyyNxtyyData.find(obj => obj.inqireDe == strtDt && obj.iemDivId == "mngAmt") || 0).inqireIemVu;
	spnPrvyyMngAmt.setLabel(ecsLib.dsplFrmt(mngAmt, 2));
	var mngReprMntnc = (prvyyNxtyyData.find(obj => obj.inqireDe == strtDt && obj.iemDivId == "mngReprMntnc") || 0).inqireIemVu;
	spnPrvyyMngReprMntnc.setLabel(ecsLib.dsplFrmt(mngReprMntnc));
	var mngRemt = (prvyyNxtyyData.find(obj => obj.inqireDe == strtDt && obj.iemDivId == "mngRemt") || 0).inqireIemVu;
	spnPrvyyMngRemt.setLabel(ecsLib.dsplFrmt(mngRemt));
	var mngChckMntnc = (prvyyNxtyyData.find(obj => obj.inqireDe == strtDt && obj.iemDivId == "mngChckMntnc") || 0).inqireIemVu;
	spnPrvyyMngChckMntnc.setLabel(ecsLib.dsplFrmt(mngChckMntnc));
	var dsuseCpcty = (prvyyNxtyyData.find(obj => obj.inqireDe == strtDt && obj.iemDivId == "dsuseComptEqpCpcty") || 0).inqireIemVu;
	spnPrvyyDsuseCpcty.setLabel(ecsLib.dsplFrmt(dsuseCpcty, 2));
	var dsuseAmt = (prvyyNxtyyData.find(obj => obj.inqireDe == strtDt && obj.iemDivId == "dsuseComptAmt") || 0).inqireIemVu;
	spnPrvyyDsuseAmt.setLabel(ecsLib.dsplFrmt(dsuseAmt, 2));
	var dsuseFoundng = (prvyyNxtyyData.find(obj => obj.inqireDe == strtDt && obj.iemDivId == "dsuseFoundngCnt") || 0).inqireIemVu;
	spnPrvyyDsuseFoundng.setLabel(ecsLib.dsplFrmt(dsuseFoundng));
	var dsusePrgs = (prvyyNxtyyData.find(obj => obj.inqireDe == strtDt && obj.iemDivId == "dsusePrgsCnt") || 0).inqireIemVu;
	spnPrvyyDsusePrgs.setLabel(ecsLib.dsplFrmt(dsusePrgs));
	var dsuseCompt = (prvyyNxtyyData.find(obj => obj.inqireDe == strtDt && obj.iemDivId == "dsuseComptCnt") || 0).inqireIemVu;
	spnPrvyyDsuseCompt.setLabel(ecsLib.dsplFrmt(dsuseCompt));

	// 후년도 데이터 매핑
	var planCpcty = (prvyyNxtyyData.find(obj => obj.inqireDe == endDt && obj.iemDivId == "planComptEqpCpcty") || 0).inqireIemVu;
	spnNxtyyPlanCpcty.setLabel(ecsLib.dsplFrmt(planCpcty, 2));
	var planAmt = (prvyyNxtyyData.find(obj => obj.inqireDe == endDt && obj.iemDivId == "planComptAmt") || 0).inqireIemVu;
	spnNxtyyPlanAmt.setLabel(ecsLib.dsplFrmt(planAmt, 2));
	var planFoundng = (prvyyNxtyyData.find(obj => obj.inqireDe == endDt && obj.iemDivId == "planFoundngCnt") || 0).inqireIemVu;
	spnNxtyyPlanFoundng.setLabel(ecsLib.dsplFrmt(planFoundng));
	var planPrgs = (prvyyNxtyyData.find(obj => obj.inqireDe == endDt && obj.iemDivId == "planPrgsCnt") || 0).inqireIemVu;
	spnNxtyyPlanPrgs.setLabel(ecsLib.dsplFrmt(planPrgs));
	var planCompt = (prvyyNxtyyData.find(obj => obj.inqireDe == endDt && obj.iemDivId == "planComptCnt") || 0).inqireIemVu;
	spnNxtyyPlanCompt.setLabel(ecsLib.dsplFrmt(planCompt));
	var cnstrcCpcty = (prvyyNxtyyData.find(obj => obj.inqireDe == endDt && obj.iemDivId == "cnstrcComptEqpCpcty") || 0).inqireIemVu;
	spnNxtyyCnstrcCpcty.setLabel(ecsLib.dsplFrmt(cnstrcCpcty, 2));
	var cnstrcAmt = (prvyyNxtyyData.find(obj => obj.inqireDe == endDt && obj.iemDivId == "cnstrcComptAmt") || 0).inqireIemVu;
	spnNxtyyCnstrcAmt.setLabel(ecsLib.dsplFrmt(cnstrcAmt, 2));
	var cnstrcFoundng = (prvyyNxtyyData.find(obj => obj.inqireDe == endDt && obj.iemDivId == "cnstrcFoundngCnt") || 0).inqireIemVu;
	spnNxtyyCnstrcFoundng.setLabel(ecsLib.dsplFrmt(cnstrcFoundng));
	var cnstrcPrgs = (prvyyNxtyyData.find(obj => obj.inqireDe == endDt && obj.iemDivId == "cnstrcPrgsCnt") || 0).inqireIemVu;
	spnNxtyyCnstrcPrgs.setLabel(ecsLib.dsplFrmt(cnstrcPrgs));
	var cnstrcCompt = (prvyyNxtyyData.find(obj => obj.inqireDe == endDt && obj.iemDivId == "cnstrcComptCnt") || 0).inqireIemVu;
	spnNxtyyCnstrcCompt.setLabel(ecsLib.dsplFrmt(cnstrcCompt));
	var mngCnt = (prvyyNxtyyData.reduce((sum, obj) => obj.inqireDe == endDt && obj.iemDivId == "mngReprMntnc" || obj.inqireDe == endDt && obj.iemDivId == "mngRemt" || obj.inqireDe == endDt && obj.iemDivId == "mngChckMntnc" ? sum + Number(obj.inqireIemVu) : sum, 0) || 0);
	spnNxtyyMngCnt.setLabel(ecsLib.dsplFrmt(mngCnt));
	var mngAmt = (prvyyNxtyyData.find(obj => obj.inqireDe == endDt && obj.iemDivId == "mngAmt") || 0).inqireIemVu;
	spnNxtyyMngAmt.setLabel(ecsLib.dsplFrmt(mngAmt, 2));
	var mngReprMntnc = (prvyyNxtyyData.find(obj => obj.inqireDe == endDt && obj.iemDivId == "mngReprMntnc") || 0).inqireIemVu;
	spnNxtyyMngReprMntnc.setLabel(ecsLib.dsplFrmt(mngReprMntnc));
	var mngRemt = (prvyyNxtyyData.find(obj => obj.inqireDe == endDt && obj.iemDivId == "mngRemt") || 0).inqireIemVu;
	spnNxtyyMngRemt.setLabel(ecsLib.dsplFrmt(mngRemt));
	var mngChckMntnc = (prvyyNxtyyData.find(obj => obj.inqireDe == endDt && obj.iemDivId == "mngChckMntnc") || 0).inqireIemVu;
	spnNxtyyMngChckMntnc.setLabel(ecsLib.dsplFrmt(mngChckMntnc));
	var dsuseCpcty = (prvyyNxtyyData.find(obj => obj.inqireDe == endDt && obj.iemDivId == "dsuseComptEqpCpcty") || 0).inqireIemVu;
	spnNxtyyDsuseCpcty.setLabel(ecsLib.dsplFrmt(dsuseCpcty, 2));
	var dsuseAmt = (prvyyNxtyyData.find(obj => obj.inqireDe == endDt && obj.iemDivId == "dsuseComptAmt") || 0).inqireIemVu;
	spnNxtyyDsuseAmt.setLabel(ecsLib.dsplFrmt(dsuseAmt, 2));
	var dsuseFoundng = (prvyyNxtyyData.find(obj => obj.inqireDe == endDt && obj.iemDivId == "dsuseFoundngCnt") || 0).inqireIemVu;
	spnNxtyyDsuseFoundng.setLabel(ecsLib.dsplFrmt(dsuseFoundng));
	var dsusePrgs = (prvyyNxtyyData.find(obj => obj.inqireDe == endDt && obj.iemDivId == "dsusePrgsCnt") || 0).inqireIemVu;
	spnNxtyyDsusePrgs.setLabel(ecsLib.dsplFrmt(dsusePrgs));
	var dsuseCompt = (prvyyNxtyyData.find(obj => obj.inqireDe == endDt && obj.iemDivId == "dsuseComptCnt") || 0).inqireIemVu;
	spnNxtyyDsuseCompt.setLabel(ecsLib.dsplFrmt(dsuseCompt));

	// 금년도 라벨 데이터 매핑
	var planCpcty = (prvyyNxtyyData.find(obj => obj.inqireDe == year && obj.iemDivId == "planComptEqpCpcty") || 0).inqireIemVu;
	spnThsyyPlanCpcty.setLabel(ecsLib.dsplFrmt(planCpcty, 2));
	var planAmt = (prvyyNxtyyData.find(obj => obj.inqireDe == year && obj.iemDivId == "planComptAmt") || 0).inqireIemVu;
	spnThsyyPlanAmt.setLabel(ecsLib.dsplFrmt(planAmt, 2));
	var cnstrcCpcty = (prvyyNxtyyData.find(obj => obj.inqireDe == year && obj.iemDivId == "cnstrcComptEqpCpcty") || 0).inqireIemVu;
	spnThsyyCnstrcCpcty.setLabel(ecsLib.dsplFrmt(cnstrcCpcty, 2));
	var cnstrcAmt = (prvyyNxtyyData.find(obj => obj.inqireDe == year && obj.iemDivId == "cnstrcComptAmt") || 0).inqireIemVu;
	spnThsyyCnstrcAmt.setLabel(ecsLib.dsplFrmt(cnstrcAmt, 2));
	var mngCnt = (prvyyNxtyyData.reduce((sum, obj) => obj.inqireDe == year && obj.iemDivId == "mngReprMntnc" || obj.inqireDe == year && obj.iemDivId == "mngRemt" || obj.inqireDe == year && obj.iemDivId == "mngChckMntnc" ? sum + Number(obj.inqireIemVu) : sum, 0) || 0);
	spnThsyyMngCnt.setLabel(ecsLib.dsplFrmt(mngCnt));
	var mngAmt = (prvyyNxtyyData.find(obj => obj.inqireDe == year && obj.iemDivId == "mngAmt") || 0).inqireIemVu;
	spnThsyyMngAmt.setLabel(ecsLib.dsplFrmt(mngAmt, 2));
	var dsuseCpcty = (prvyyNxtyyData.find(obj => obj.inqireDe == year && obj.iemDivId == "dsuseComptEqpCpcty") || 0).inqireIemVu;
	spnThsyyDsuseCpcty.setLabel(ecsLib.dsplFrmt(dsuseCpcty, 2));
	var dsuseAmt = (prvyyNxtyyData.find(obj => obj.inqireDe == year && obj.iemDivId == "dsuseComptAmt") || 0).inqireIemVu;
	spnThsyyDsuseAmt.setLabel(ecsLib.dsplFrmt(dsuseAmt, 2));
};

/**
 * 금년도의 데이터 조회_0926
 */
scwin.searchThsyyData = function(year) {
	var strtDt = year;
	var endDt = year;

	var queryString = `?strtDt=${strtDt}`;
	queryString += `&endDt=${endDt}`;

	var option = {
		action : "ec/pbme/retrieve-pbme-sttus-setcsc.do" +
			queryString,
		method : "get",
		resData : dltThsyyPlanList,
		success : "scwin.searchThsyyDataCallBack",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
 * 금년도의 데이터 조회 콜백_0926
 */
scwin.searchThsyyDataCallBack = function() {
	var thsyyPlanData = dltThsyyPlanList.getAllJSON();
	var planData = thsyyPlanData.filter(obj => obj.cmmnCdNm.startsWith("plan"));
	var cnstrcData = thsyyPlanData.filter(obj => obj.cmmnCdNm.startsWith("cnstrc"));
	var mngData = thsyyPlanData.filter(obj => obj.cmmnCdNm.startsWith("mng"));
	var dsuseData = thsyyPlanData.filter(obj => obj.cmmnCdNm.startsWith("dsuse"));

	dltThsyyPlanList.setJSON(planData);
	dltThsyyCnstrcList.setJSON(cnstrcData);
	dltThsyyMngList.setJSON(mngData);
	dltThsyyDsuseList.setJSON(dsuseData);
